// app/dashboard/accountant/layout.tsx
import type { ReactNode } from "react";
import AccountantSidebar from "./_components/accountant-sidebar";

export default function AccountantLayout({ children }: { children: ReactNode }) {
  return (
    <div className="min-h-screen bg-gray-50">
      <div className="flex">
        {/* Sidebar */}
        <aside className="hidden md:block w-64 border-r border-gray-200 bg-white">
          <AccountantSidebar />
        </aside>

        {/* Content */}
        <main className="flex-1">{children}</main>
      </div>
    </div>
  );
}